import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { usePatient } from "../context/PatientContext";

export default function SignUpScreen() {
  const navigate = useNavigate();
  const { setName } = usePatient();
  const [input, setInput] = useState("");
  const [error, setError] = useState("");

  const handleContinue = () => {
    if (!input.trim()) {
      setError("Please enter your name");
      return;
    }
    setName(input.trim());
    localStorage.setItem("synova-name", input.trim());
    navigate("/onboarding");
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "#0a3d3d",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      position: "relative",
      overflow: "hidden",
      padding: "40px 32px",
    }}>

      {/* Background circles */}
      <div style={{
        position: "absolute", top: -60, right: -60,
        width: 200, height: 200, borderRadius: "50%",
        background: "#1a5454", opacity: 0.8,
      }} />
      <div style={{
        position: "absolute", bottom: -80, left: -60,
        width: 220, height: 220, borderRadius: "50%",
        background: "#1a5454", opacity: 0.8,
      }} />

      {/* Back button */}
      <button
        onClick={() => navigate("/")}
        style={{
          position: "absolute", top: 48, left: 32,
          background: "none", border: "none",
          color: "#b2f0e8", fontSize: 14, cursor: "pointer",
          display: "flex", alignItems: "center", gap: 6,
          opacity: 0.7, zIndex: 1,
        }}
      >
        ← Back
      </button>

      {/* Logo */}
      <div style={{ textAlign: "center", marginBottom: 48, zIndex: 1 }}>
        <div style={{
          fontFamily: "'Pacifico', cursive",
          fontSize: 42,
          color: "#b2f0e8",
          marginBottom: 8,
        }}>
          synova
        </div>
        <div style={{
          color: "#b2f0e8", fontSize: 15, opacity: 0.7,
        }}>
          Let's get you set up
        </div>
      </div>

      {/* Form */}
      <div style={{ width: "100%", maxWidth: 340, zIndex: 1 }}>

        <div style={{ marginBottom: 24 }}>
          <label style={{
            display: "block",
            color: "#b2f0e8", fontSize: 12, fontWeight: 600,
            letterSpacing: 1.5, textTransform: "uppercase",
            marginBottom: 10, opacity: 0.7,
          }}>
            Your name
          </label>
          <input
            type="text"
            value={input}
            onChange={(e) => { setInput(e.target.value); setError(""); }}
            onKeyDown={(e) => e.key === "Enter" && handleContinue()}
            placeholder="e.g. Margaret"
            style={{
              width: "100%",
              padding: "18px 20px",
              borderRadius: 16,
              background: "#1a5454",
              border: error ? "1.5px solid #ff6b6b" : "1.5px solid #2a6464",
              color: "#b2f0e8",
              fontSize: 18,
              outline: "none",
              boxSizing: "border-box",
            }}
          />
          {error && (
            <div style={{ color: "#ff8888", fontSize: 12, marginTop: 6, paddingLeft: 4 }}>
              {error}
            </div>
          )}
        </div>

        <button
          onClick={handleContinue}
          style={{
            width: "100%",
            padding: "20px",
            borderRadius: 50,
            background: "#1a5c5c",
            border: "none",
            color: "#b2f0e8",
            fontSize: 16,
            fontWeight: 700,
            letterSpacing: 1.5,
            textTransform: "uppercase",
            cursor: "pointer",
          }}
        >
          Continue
        </button>

        <div style={{
          textAlign: "center", marginTop: 20,
          color: "#b2f0e8", fontSize: 12, opacity: 0.5,
        }}>
          Already have an account?{" "}
          <span
            onClick={() => navigate("/login-form")}
            style={{ opacity: 1, cursor: "pointer", textDecoration: "underline" }}
          >
            Log in
          </span>
        </div>

      </div>
    </div>
  );
}
